describe('notification ordering', () => {
  it('should deliver notifications in order even when events fire concurrently', async () => {
    // Create an adapter with artificial delay on the first call to simulate
    // a slow delivery that could cause reordering without a queue.
    let callCount = 0;
    const deliveryOrder: string[] = [];
    const slowEmailAdapter = new EmailAdapter({
      transport: async (email) => {
        callCount++;
        if (callCount === 1) {
          // First notification is slow — without ordering, the second could overtake it.
          await new Promise((resolve) => setTimeout(resolve, 50));
        }
        deliveryOrder.push(email.subject);
        return 'msg-' + callCount;
      },
    });

    const orderedService = new NotificationService(eventBus);
    orderedService.registerAdapter(slowEmailAdapter);

    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'alice@example.com',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Fire both events concurrently — the order:created handler is slow,
    // but the queue should ensure it completes before the status change.
    await Promise.all([
      eventBus.emit(orderCreatedEvent),
      eventBus.emit(statusChangedEvent),
    ]);

    // The "Order Confirmation" must be delivered before "Order Update"
    expect(deliveryOrder[0]).toContain('Order Confirmation');
    expect(deliveryOrder[1]).toContain('Order Update');

    const notifications = orderedService.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[0]?.type).toBe('order_confirmation');
    expect(notifications[1]?.type).toBe('order_status_update');
  });
});

